247‚Üí                flex: 1, padding: '12px', borderRadius: '10px', border: '2px solid',
248‚Üí                borderColor: callForm.signal_type === st.value ? st.color : 'rgba(255,255,255,0.1)',
249‚Üí                background: callForm.signal_type === st.value ? `${st.color}22` : 'rgba(255,255,255,0.03)',
250‚Üí                color: callForm.signal_type === st.value ? st.color : 'var(--text-muted)',
251‚Üí                cursor: 'pointer', fontWeight: 700, fontSize: '0.8rem', textAlign: 'center'
252‚Üí              }}>
